const item = $input.first().json;
const inputText = (item.input_text || '').trim();
const preferedLang = inputText.startsWith('lang_') 
  ? inputText.substring(5) 
  : '';

return [{
  json: {
    ...item,
    prefered_lang: preferedLang
  }
}];

